const query = $('Webhook').first().json.query;
const barbero = query.barbero;
const fecha = query.fecha;

const reservas = $('Leer Reservas').all().map(i => i.json);
const bloqueos = $('Leer Bloqueos').all().map(i => i.json);

// Comprobar si el día está cerrado por completo
const diaCerrado = bloqueos.some(b =>
  b.fecha === fecha &&
  b.tipo === 'dia_completo' &&
  (String(b.empleadoId) === '0' || b.empleadoId === barbero)
);

if (diaCerrado) {
  return [{ json: { diaCerrado: true } }];
}

// Horas ocupadas por reservas existentes
// Nota: columnas de Hoja 1 con mayúscula (Fecha, Barbero, Hora)
const horasReservas = reservas
  .filter(r => r.Fecha === fecha && r.Barbero === barbero)
  .map(r => r.Hora);

// Horas bloqueadas por rangos horarios
const SLOT = 30;
const horasBloqueos = [];
bloqueos
  .filter(b =>
    b.fecha === fecha &&
    b.tipo === 'horas' &&
    (String(b.empleadoId) === '0' || b.empleadoId === barbero) &&
    b.inicio && b.fin
  )
  .forEach(b => {
    const [sh, sm] = b.inicio.split(':').map(Number);
    const [eh, em] = b.fin.split(':').map(Number);
    let cur = sh * 60 + sm;
    const end = eh * 60 + em;
    while (cur < end) {
      horasBloqueos.push(
        String(Math.floor(cur / 60)).padStart(2, '0') + ':' +
        String(cur % 60).padStart(2, '0')
      );
      cur += SLOT;
    }
  });

const horasOcupadas = [...new Set([...horasReservas, ...horasBloqueos])];
return [{ json: { horasOcupadas } }];
